Bash(/opt/homebrew/opt/node/bin/node -e "
import\('./src/market/taIndicators.js'\).then\(m => {
  // Test Supertrend
  const closes = [10,11,10.5,12,11.5,13,12,14,13.5,15,14,16,15,17,16,18,17,19,18,20];
  const highs  = closes.map\(c => c * 1.02\);
  const lows   = closes.map\(c => c * 0.98\);
  const st = m.computeSupertrend\(highs, lows, closes, 5, 2\);
  console.log\('Supertrend:', JSON.stringify\(st\)\);

  // Test MACD
  const longCloses = Array.from\({length: 50}, \(_, i\) => 10 + i * 0.3 + Math.sin\(i\) * 2\);
  const macd = m.computeMACD\(longCloses, 12, 26, 9\);
  console.log\('MACD histogram:', macd?.histogram, '| firstGreenAfterRed:', macd?.firstGreenAfterRed\);

  // Test detectEvilPandaSignals
  const candles = Array.from\({length: 60}, \(_, i\) => \({
    t: i, o: 10 + i * 0.1, h: 10.2 + i * 0.1, l: 9.8 + i * 0.1, c: 10.05 + i * 0.1, v: 1000
  }\)\);
  const ep = m.detectEvilPandaSignals\(candles\);
  console.log\('EP exit triggered:', ep.exit.triggered, '|', ep.exit.reason\);
  console.log\('EP entry:', ep.entry?.reason\);
}\).catch\(e => console.error\('❌', e.message, e.stack\)\);
" 2>&1)

